        .log-entry.info { border-color:#58a6ff; }
        .log-entry.warn { border-color:#d29922; }
        .log-entry.error { border-color:#f85149; }
        .log-entry.success { border-color:#3fb950; }
        /* Toast notification */
        .toast-container { position:fixed; top:60px; right:24px; z-index:9999; display:flex; flex-direction:column; gap:8px; }
        .toast { padding:12px 20px; border-radius:8px; font-size:14px; animation:slideIn 0.3s ease; min-width:250px; max-width:400px; }
        .toast.success { background:#1a4731; border:1px solid #3fb950; color:#3fb950; }
        .toast.error { background:#4d1c1a; border:1px solid #f85149; color:#f85149; }
        .toast.info { background:#1a3a52; border:1px solid #58a6ff; color:#58a6ff; }
        .toast.warning { background:#4a3a1a; border:1px solid #d29922; color:#d29922; }
        @keyframes slideIn { from { transform:translateX(100%); opacity:0; } to { transform:translateX(0); opacity:1; } }
        /* Modal */
        .modal-backdrop { position:fixed; top:0; left:0; width:100%; height:100%; background:rgba(0,0,0,0.6); z-index:9000; display:flex; align-items:center; justify-content:center; }
        .modal { background:#161b22; border:1px solid #30363d; border-radius:12px; padding:24px; width:400px; max-width:90vw; }
        .modal h3 { margin-bottom:16px; font-size:18px; }
        .modal .btn-group { justify-content:flex-end; margin-top:20px; }
        /* Loading spinner */
        .spinner { display:inline-block; width:16px; height:16px; border:2px solid #30363d; border-top-color:#58a6ff; border-radius:50%; animation:spin 0.8s linear infinite; }
        @keyframes spin { to { transform:rotate(360deg); } }
        .loading { pointer-events:none; opacity:0.7; }
        /* Device actions */
        .actions { display:flex; gap:4px; flex-wrap:wrap; }
        /* PTZ status panel */
        .ptz-position { text-align:center; padding:12px; background:#0d1117; border-radius:8px; margin:12px 0; font-family:monospace; font-size:14px; }
        .toolbar { display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:16px; flex-wrap:wrap; }
        .toolbar-actions { display:flex; gap:8px; }
        .device-info-panel { background:#0d1117; border-radius:8px; padding:16px; margin-top:12px; font-size:13px; }
        .device-info-panel .info-row { display:flex; justify-content:space-between; padding:4px 0; border-bottom:1px solid #21262d; }
        .device-info-panel .info-row:last-child { border-bottom:none; }
        .device-info-panel .info-label { color:#8b949e; }
        .device-info-panel .info-value { color:#e0e6f0; font-family:monospace; }
        @media (max-width:768px) { .grid { grid-template-columns:1fr 1fr; } .header { flex-direction:column; gap:8px; } .nav { overflow-x:auto; } .console-layout { flex-direction:column !important; } .console-left, .console-center, .console-right { width:100% !important; } }
        /* Console page: left-right layout (SPEC: left=joystick, right=display) */
        .console-layout { display:flex; gap:20px; align-items:flex-start; }
        .console-left { flex:0 0 320px; display:flex; flex-direction:column; min-width:0; overflow:hidden; }
        .console-center { flex:1; min-width:0; display:flex; flex-direction:column; }
        .console-right { flex:0 0 25%; max-width:300px; display:flex; flex-direction:column; }
        /* WASM 播放器容器: 强制子元素填满, 保持 16:9 */
        #divPlugin { width:100%; aspect-ratio:16/9; display:block; overflow:hidden; }
        #divPlugin .parent-wnd { width:100% !important; height:100% !important; }
        #divPlugin .parent-wnd > div { width:100% !important; height:100% !important; border:none !important; }
        #divPlugin .video-container { width:100% !important; height:100% !important; }
        #divPlugin canvas.play-window { width:100% !important; height:100% !important; }
    </style>
