        // v7.15: 快速添加设备
        window.quickAddDevice = function(ip, gateway) {
            showQuickAddModal(ip, gateway);
        };
        // v7.15: 显示快速添加设备模态框
        window.showQuickAddModal = function(ip, gateway) {
            var localhostGateway = window.localhostGateway || gateway || '';
            var modalHtml = '<div id="quickAddModal" class="modal-overlay" onclick="closeQuickAddModal(event)" style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:10000">' +
                '<div class="modal-content" onclick="event.stopPropagation()" style="background:#1a1e2e;padding:24px;border-radius:12px;min-width:360px;box-shadow:0 4px 20px rgba(0,0,0,0.5)">' +
                '<h3 style="margin:0 0 20px 0;color:#58a6ff;font-size:18px">添加设备</h3>' +
                '<div style="margin-bottom:16px"><label style="display:block;margin-bottom:6px;color:#8b949e;font-size:13px">IP 地址</label>' +
                '<input type="text" id="quickAddIp" value="' + (ip || '') + '" style="width:100%;padding:10px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:6px;font-size:14px"></div>' +
                '<div style="margin-bottom:16px"><label style="display:block;margin-bottom:6px;color:#8b949e;font-size:13px">网关</label>' +
                '<input type="text" id="quickAddGateway" value="' + localhostGateway + '" style="width:100%;padding:10px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:6px;font-size:14px"></div>' +
                '<div style="margin-bottom:16px"><label style="display:block;margin-bottom:6px;color:#8b949e;font-size:13px">用户名</label>' +
                '<input type="text" id="quickAddUser" value="admin" style="width:100%;padding:10px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:6px;font-size:14px"></div>' +
                '<div style="margin-bottom:20px"><label style="display:block;margin-bottom:6px;color:#8b949e;font-size:13px">密码</label>' +
                '<input type="password" id="quickAddPass" style="width:100%;padding:10px;background:#0d1117;border:1px solid #30363d;color:#e0e6f0;border-radius:6px;font-size:14px"></div>' +
                '<div style="display:flex;gap:12px;justify-content:flex-end">' +
                '<button class="btn btn-secondary" onclick="closeQuickAddModal()" style="padding:8px 16px">取消</button>' +
                '<button class="btn btn-primary" onclick="submitQuickAdd()" style="padding:8px 16px">添加并连接</button></div></div></div>';
            document.body.insertAdjacentHTML('beforeend', modalHtml);
        };
        window.closeQuickAddModal = function(e) {
            if (e && e.target !== e.currentTarget) return;
            var modal = document.getElementById('quickAddModal');
            if (modal) modal.remove();
        };
        window.submitQuickAdd = function() {
            var ip = document.getElementById('quickAddIp').value.trim();
            var gateway = document.getElementById('quickAddGateway').value.trim();
            var username = document.getElementById('quickAddUser').value.trim();
            var password = document.getElementById('quickAddPass').value;
            if (!ip) { addLog('error', '请输入 IP 地址'); return; }
            if (!password) { addLog('error', '请输入密码'); return; }
            closeQuickAddModal();
            apiPost('/api/v1/devices', {ip: ip, gateway: gateway, username: username, password: password})
                .then(function(result) {
                    if (result.success) {
                        addLog('done', '设备已添加: ' + ip);
                        refreshDevices();
                        setTimeout(function() { connectDevice(ip); }, 500);
                    } else {
                        addLog('error', result.message || '添加失败');
                    }
                }).catch(function(e) { addLog('error', '添加设备失败: ' + e); });
        };
        // v7.15: 添加设备按钮（完整输入）
        window.showAddDeviceModal = function() {
            showQuickAddModal('', '');
        };
        // v6.35: 显示设备信息弹窗
        window.showDeviceInfoModal = function(ip) {
            var d = allDevices.find(function(dev) { return dev.ip === ip; }) || {};
            var info = '<div style="font-size:14px;line-height:1.8">' +
                '<p><b>IP:</b> ' + (d.ip || '--') + '</p>' +
                '<p><b>MAC:</b> ' + (d.mac || '--') + '</p>' +
                '<p><b>名称:</b> ' + (d.name || d.device_name || '--') + '</p>' +
                '<p><b>型号:</b> ' + (d.model || '--') + '</p>' +
                '<p><b>网关:</b> ' + (d.gateway || '--') + '</p>' +
                '<p><b>子网掩码:</b> ' + (d.subnet || '--') + '</p>' +
                '<p><b>端口:</b> ' + (d.port || 80) + '</p>' +
                '</div>';
            if (window.showModal) {
                showModal('设备信息', info);
            } else {
                if (window.showAlert) window.showAlert(info, '设备信息');
            }
        };
        // v6.54: 连接/断开操作锁
        var _connectionOperationInProgress = false;

        // Device Actions
        function connectDevice(ip) {
            // v6.54: 防止重复点击
            if (_connectionOperationInProgress) {
                showToast('warning', '请等待上一次操作完成');
                return;
            }
            _connectionOperationInProgress = true;

            addLog('info', '正在连接设备: ' + ip);
            showToast('info', '正在连接设备...');

            // 禁用连接按钮
            if (window.setConnectionButtonsEnabled) window.setConnectionButtonsEnabled(false);

