        function setTracking(mode) {
            var dev = window.connectedDevice.ip;
            if (!dev) { showToast('warning', '请先在上方选择已连接设备'); return; }
            // 重置按钮状态
            ['btnTrackSidereal','btnTrackLunar','btnTrackSolar','btnTrackOff'].forEach(function(id) {
                var b = document.getElementById(id);
                if(b) { b.className = 'btn btn-secondary'; b.style.opacity = '1'; }
            });
            apiPost('/api/v1/ascom/telescope/tracking?mode=' + mode, null).then(function(result) {
                var trackLabels = {trackSidereal:'恒星跟踪',trackLunar:'月球跟踪',trackSolar:'太阳跟踪',trackOff:'关闭跟踪'};
                if (typeof operationLog === 'function') operationLog('跟踪: ' + (trackLabels[mode] || mode), 'success');
                if (result && result.success) {
                    showToast('success', result.message || '跟踪模式已设置');
                    // 高亮当前按钮
                    var btnMap = {trackSidereal:'btnTrackSidereal',trackLunar:'btnTrackLunar',trackSolar:'btnTrackSolar',trackOff:'btnTrackOff'};
                    var activeBtn = document.getElementById(btnMap[mode]);
                    if (activeBtn) { activeBtn.className = 'btn btn-primary'; }
                } else {
                    // 对于非ASCOM望远镜,给UI反馈
                    showToast('info', '跟踪模式: ' + mode + ' (设备响应: ' + (result ? result.message : '无') + ')');
                    var btnMap = {trackSidereal:'btnTrackSidereal',trackLunar:'btnTrackLunar',trackSolar:'btnTrackSolar',trackOff:'btnTrackOff'};
                    var activeBtn = document.getElementById(btnMap[mode]);
                    if (activeBtn) { activeBtn.className = 'btn btn-primary'; }
                }
            }).catch(function(e) {
                showToast('info', '跟踪模式: ' + mode + ' (API未响应)');
                var btnMap = {trackSidereal:'btnTrackSidereal',trackLunar:'btnTrackLunar',trackSolar:'btnTrackSolar',trackOff:'btnTrackOff'};
                var activeBtn = document.getElementById(btnMap[mode]);
                if (activeBtn) { activeBtn.className = 'btn btn-primary'; }
            });
        }
