window.showModal = function(options) {
    var title = options.title || '';
    var body = options.body || '';
    var titleColor = options.titleColor || '#58a6ff';
    var buttons = options.buttons || [];
    var modalId = 'astroModal_' + Date.now();

    var btnHtml = '';
    buttons.forEach(function(btn) {
        var cls = btn.cls || 'btn-secondary';
        var onclick = 'window._modalClose("' + modalId + '", ' + (btn.callback ? 'true' : 'false') + ')';
        btnHtml += '<button class="btn ' + cls + '" onclick="' + onclick + '">' + btn.text + '</button>';
    });

    var html = '<div id="' + modalId + '" class="astro-modal-backdrop">' +
        '<div class="astro-modal">' +
        '<h3 class="astro-modal-title" style="color:' + titleColor + '">' + title + '</h3>' +
        '<div class="astro-modal-body">' + body + '</div>' +
        '<div class="astro-modal-actions">' + btnHtml + '</div>' +
        '</div></div>';

    document.body.insertAdjacentHTML('beforeend', html);

    // Store callbacks
    window._modalCallbacks = window._modalCallbacks || {};
    window._modalCallbacks[modalId] = buttons;

    // ESC handler
    var escHandler = function(e) {
        if (e.key === 'Escape') {
            window._modalClose(modalId, false);
        }
    };
    document.addEventListener('keydown', escHandler, {once: true});
    window._modalEscHandlers = window._modalEscHandlers || {};
    window._modalEscHandlers[modalId] = escHandler;

    return modalId;
};

window._modalClose = function(modalId, triggerCallback) {
    var modal = document.getElementById(modalId);
    if (!modal) return;

    // Remove ESC handler
    if (window._modalEscHandlers && window._modalEscHandlers[modalId]) {
        document.removeEventListener('keydown', window._modalEscHandlers[modalId]);
        delete window._modalEscHandlers[modalId];
    }

    // Execute callback if needed
    if (triggerCallback && window._modalCallbacks && window._modalCallbacks[modalId]) {
        var buttons = window._modalCallbacks[modalId];
        // Find button with callback
        for (var i = 0; i < buttons.length; i++) {
            if (buttons[i].callback) {
                buttons[i].callback();
                break;
            }
        }
        delete window._modalCallbacks[modalId];
    }

    modal.remove();
};

window.showAlert = function(message, title) {
