window._modalCallbacks = {};

window._modalClose = function(modalId, callbackIndex) {
    var callbacks = window._modalCallbacks[modalId];
    if (!callbacks) return;

    var cb = callbacks[callbackIndex];
    if (cb) cb();

    // Cleanup
    delete window._modalCallbacks[modalId];
    var modal = document.getElementById(modalId);
    if (modal) modal.remove();
};

window.showModal = function(options) {
    var title = options.title || '';
    var body = options.body || '';
    var titleColor = options.titleColor || '#58a6ff';
    var buttons = options.buttons || [];
    var modalId = 'astroModal_' + Date.now();

    // Store callbacks by index
    window._modalCallbacks[modalId] = buttons.map(function(b) { return b.callback || null; });

    var btnHtml = '';
    buttons.forEach(function(btn, i) {
        var cls = btn.cls || 'btn-secondary';
        btnHtml += '<button class="btn ' + cls + '" onclick="window._modalClose(\'' + modalId + '\', ' + i + ')">' + btn.text + '</button>';
    });

    var html = '<div id="' + modalId + '" class="astro-modal-backdrop">' +
        '<div class="astro-modal">' +
        '<h3 class="astro-modal-title" style="color:' + titleColor + '">' + title + '</h3>' +
        '<div class="astro-modal-body">' + body + '</div>' +
        '<div class="astro-modal-actions">' + btnHtml + '</div>' +
        '</div></div>';

    document.body.insertAdjacentHTML('beforeend', html);

    // ESC handler
    var escHandler = function(e) {
        if (e.key === 'Escape') {
            window._modalClose(modalId, -1);  // -1 = no callback
        }
    };
    document.addEventListener('keydown', escHandler, {once: true});

    return modalId;
};
```

