// v7.117: 统一弹窗组件 — 替代所有旧弹窗
// options: { type:'alert'|'confirm'|'form', title, message, fields, onConfirm, onCancel }
window.showModal = function(options) {
    closeModal();
    var opts = options || {};
    var type = opts.type || 'alert';
    var title = opts.title || (type === 'confirm' ? '确认' : '提示');
    var titleColor = type === 'confirm' ? '#58a6ff' : '#f0883e';
    var bodyHtml = '';

    if (type === 'form' && opts.fields) {
        opts.fields.forEach(function(f) {
            bodyHtml += '<div class="astro-modal-field"><label>' + (f.label || '') + '</label>' +
                '<input type="' + (f.type || 'text') + '" id="astroModalField_' + (f.id || '') + '"' +
                ' value="' + (f.value || '') + '" placeholder="' + (f.placeholder || '') + '"' +
                (f.required ? ' required' : '') + '></div>';
        });
    } else if (opts.message) {
        bodyHtml = '<p class="astro-modal-body">' + opts.message + '</p>';
    }

    var actionsHtml = '';
    if (type === 'confirm' || type === 'form') {
        actionsHtml = '<button class="btn btn-secondary" onclick="closeModal(false)">取消</button>' +
            '<button class="btn btn-primary" onclick="closeModal(true)">确定</button>';
    } else {
        actionsHtml = '<button class="btn btn-primary" onclick="closeModal(true)" style="width:100%">确定</button>';
    }

    var html = '<div id="astroModal" class="astro-modal-backdrop">' +
        '<div class="astro-modal">' +
        '<h3 class="astro-modal-title" style="color:' + titleColor + '">' + title + '</h3>' +
        bodyHtml +
        '<div class="astro-modal-actions">' + actionsHtml + '</div>' +
        '</div></div>';
    document.body.insertAdjacentHTML('beforeend', html);
    window._modalCallback = opts.onConfirm || null;
    window._modalType = type;

    // ESC 关闭
    window._modalEscHandler = function(e) { if (e.key === 'Escape') closeModal(false); };
    document.addEventListener('keydown', window._modalEscHandler);

    // 聚焦第一个输入框
    if (type === 'form') {
        setTimeout(function() {
            var firstInput = document.querySelector('#astroModal input');
            if (firstInput) firstInput.focus();
        }, 100);
    }
};
window.closeModal = function(result) {
    var modal = document.getElementById('astroModal');
    if (modal) modal.remove();
    if (window._modalEscHandler) {
        document.removeEventListener('keydown', window._modalEscHandler);
        window._modalEscHandler = null;
    }
    if (result && window._modalCallback) {
        if (window._modalType === 'form') {
            var data = {};
            var inputs = document.querySelectorAll('#astroModal [id^="astroModalField_"]');
            inputs.forEach(function(el) {
                var key = el.id.replace('astroModalField_', '');
                data[key] = el.value;
            });
            window._modalCallback(data);
        } else {
            window._modalCallback();
        }
    }
    window._modalCallback = null;
    window._modalType = null;
};
// 兼容旧接口
window.showAlert = function(message, title) { showModal({ type:'alert', title:title, message:message }); };
window.showConfirm = function(message, onConfirm, title) { showModal({ type:'confirm', title:title, message:message, onConfirm:onConfirm }); };
window.closeAlert = function() { closeModal(false); };
window.closeConfirm = function(result) { closeModal(result); };

