// v7.117: 快速添加设备 — 使用统一弹窗
window.showQuickAddModal = function(ip, gateway) {
    var localhostGateway = window.localhostGateway || gateway || '';
    showModal({
        type: 'form',
        title: '添加设备',
        fields: [
            { id:'quickAddIp', label:'IP 地址', value: ip || '', placeholder: '' },
            { id:'quickAddGateway', label:'网关', value: localhostGateway, placeholder: '' },
            { id:'quickAddUser', label:'用户名', value: 'admin', placeholder: '' },
            { id:'quickAddPass', label:'密码', type:'password', value: '', placeholder: '', required:true }
        ],
        onConfirm: function(data) {
            var ip = (data.quickAddIp || '').trim();
            var gateway = (data.quickAddGateway || '').trim();
            var username = (data.quickAddUser || '').trim();
            var password = data.quickAddPass;
            if (!ip) { addLog('error', '请输入 IP 地址'); return; }
            if (!password) { addLog('error', '请输入密码'); return; }
            apiPost('/api/v1/devices', {ip: ip, gateway: gateway, username: username, password: password})
                .then(function(result) {
                    if (result.success) {
                        addLog('done', '设备已添加: ' + ip);
                        refreshDevices();
                        setTimeout(function() { connectDevice(ip); }, 500);
                    } else {
                        addLog('error', result.message || '添加失败');
                    }
                }).catch(function(e) { addLog('error', '添加设备失败: ' + e); });
        }
    });
};
window.closeQuickAddModal = function() { closeModal(false); };
window.submitQuickAdd = function() { closeModal(true); };
// v7.15: 添加设备按钮（完整输入）
window.showAddDeviceModal = function() {
    showQuickAddModal('', '');
};

