function ptzWritePreset() {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) { showToast('warning', '请先连接设备'); return; }
    showModal({
        type: 'form',
        title: '写入预置点',
        fields: [
            { id:'presetId', label:'预置点编号', value:'', placeholder:'1-300', required:true },
            { id:'presetName', label:'名称', value:'', placeholder:'选填' }
        ],
        onConfirm: function(data) {
            var presetId = parseInt(data.presetId);
            var presetName = (data.presetName || '').trim();
            if (!presetId || presetId < 1 || presetId > 300) {
                showToast('error', '预置点编号需在 1-300 之间');
                return;
            }
            var resultDiv = document.getElementById('ptzPresetResult');
            if (resultDiv) resultDiv.textContent = '写入预置点 ' + presetId + '...';
            var url = '/api/v1/ptz/' + dev + '/preset/' + presetId + '/set';
            if (presetName) url += '?name=' + encodeURIComponent(presetName);
            apiPost(url, null).then(function(resp) {
                if (resp && resp.success) {
                    if (resultDiv) resultDiv.innerHTML = '<span style="color:#3fb950">✅ 已写入预置点 ' + presetId + (presetName ? ' (' + presetName + ')' : '') + '</span>';
                    if (typeof operationLog === 'function') operationLog('预置点: 写入 #' + presetId + (presetName ? ' ' + presetName : ''), 'success');
                    loadPresetList();
                } else {
                    if (resultDiv) resultDiv.innerHTML = '<span style="color:#f85149">❌ 写入失败: ' + (resp ? resp.message : '未知') + '</span>';
