function renderSpeedResults(results) {
    var area = document.getElementById('speedResultArea');
    if (!results || Object.keys(results).length === 0) {
        area.innerHTML = '<div class="advanced-status-panel"><p style="color:#6e7681">暂无结果</p></div>';
        return;
    }
    var html = '<div class="advanced-status-panel"><h4>速度测试结果</h4>';
    // 按Zoom分组交叉表
    var byZoom = results.by_zoom || {};
    if (byZoom && Object.keys(byZoom).length > 0) {
        html += _renderSpeedByZoom(byZoom);
    }
    // 总体 + Pan/Tilt汇总
    var speedMap = results.speed_map || results.speed_mapping || {};
    html += _renderSpeedTable('📊 总体', speedMap);
    var panMap = results.pan_speed || {};
    html += _renderSpeedTable('🔵 Pan轴', panMap);
    var tiltMap = results.tilt_speed || {};
    html += _renderSpeedTable('🟠 Tilt轴', tiltMap);
    html += '<div class="status-row"><span class="status-label">测试总数</span><span class="status-value">' + (results.total_tests || '--') + '</span></div>';
    html += '</div>';
    area.innerHTML = html;
}
function _renderSpeedByZoom(byZoom) {
    // byZoom: {zoom_val: {pan: {speed: val}, tilt: {speed: val}}}
    var zooms = Object.keys(byZoom).sort(function(a,b){return parseInt(a)-parseInt(b)});
    if (zooms.length === 0) return '';
    // 收集所有速度档位
    var allSpeeds = {};
    zooms.forEach(function(z) {
        var zd = byZoom[z];
        ['pan','tilt'].forEach(function(ax) {
            var am = zd[ax] || {};
            Object.keys(am).forEach(function(s) { allSpeeds[s] = true; });
        });
    });
    var speedLevels = Object.keys(allSpeeds).sort(function(a,b){return parseInt(a)-parseInt(b)});
    if (speedLevels.length === 0) return '';
    var h = '<div style="margin-bottom:12px"><strong style="color:#e0e6f0;font-size:13px">📐 按Zoom分组</strong>';
    h += '<table class="result-table" style="margin:6px 0;font-size:11px"><thead><tr><th>档位</th>';
    zooms.forEach(function(z) {
        h += '<th style="text-align:center">Z=' + z + '<br>Pan</th><th style="text-align:center">Z=' + z + '<br>Tilt</th>';
    });
    h += '</tr></thead><tbody>';
    speedLevels.forEach(function(sl) {
        h += '<tr><td>' + sl + '</td>';
        zooms.forEach(function(z) {
            var zd = byZoom[z];
            var pv = zd.pan && zd.pan[sl] != null ? zd.pan[sl] : '--';
            var tv = zd.tilt && zd.tilt[sl] != null ? zd.tilt[sl] : '--';
            h += '<td style="text-align:center">' + pv + '</td><td style="text-align:center">' + tv + '</td>';
        });
        h += '</tr>';
    });
    h += '</tbody></table></div>';
    return h;
}

